--
-- Name: apply_event(uuid); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.apply_event(p_event_id uuid) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_event second_brain.update_journal%ROWTYPE;
  v_payload jsonb;
  v_result jsonb;
BEGIN
  SELECT *
  INTO v_event
  FROM second_brain.update_journal
  WHERE event_id = p_event_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'code', 'EVENT_NOT_FOUND', 'message', 'event_id not found');
  END IF;

  IF v_event.state IN ('applied','duplicate','rejected') THEN
    RETURN jsonb_build_object(
      'ok', true,
      'code', 'NO_OP',
      'message', 'Event already in terminal state',
      'data', jsonb_build_object('event_id', v_event.event_id, 'state', v_event.state),
      'meta', jsonb_build_object('journal_offset', v_event.journal_offset, 'trace_id', v_event.trace_id)
    );
  END IF;

  IF v_event.dry_run THEN
    UPDATE second_brain.update_journal
    SET state = 'proposed',
        state_reason = 'DRY_RUN',
        replayable = true
    WHERE event_id = v_event.event_id;

    INSERT INTO second_brain.update_outcomes(event_id, outcome_state, code, message, payload)
    VALUES (v_event.event_id, 'proposed', 'DRY_RUN_PROPOSED', 'Dry run event recorded but not applied', '{}'::jsonb);

    RETURN jsonb_build_object(
      'ok', true,
      'code', 'DRY_RUN_PROPOSED',
      'message', 'Event marked as proposed because dry_run=true',
      'data', jsonb_build_object('event_id', v_event.event_id),
      'meta', jsonb_build_object('journal_offset', v_event.journal_offset, 'trace_id', v_event.trace_id)
    );
  END IF;

  IF v_event.risk_level IN ('medium','high') THEN
    UPDATE second_brain.update_journal
    SET state = 'proposed',
        state_reason = 'REQUIRES_REVIEW',
        replayable = true
    WHERE event_id = v_event.event_id;

    INSERT INTO second_brain.update_outcomes(event_id, outcome_state, code, message, payload)
    VALUES (v_event.event_id, 'proposed', 'REVIEW_REQUIRED', 'Event requires review before apply', '{}'::jsonb);

    RETURN jsonb_build_object(
      'ok', true,
      'code', 'REVIEW_REQUIRED',
      'message', 'Event moved to proposed queue',
      'data', jsonb_build_object('event_id', v_event.event_id, 'risk_level', v_event.risk_level),
      'meta', jsonb_build_object('journal_offset', v_event.journal_offset, 'trace_id', v_event.trace_id)
    );
  END IF;

  BEGIN
    v_payload := COALESCE(v_event.request -> 'payload', '{}'::jsonb);
    v_result := second_brain.process_intent(v_event.event_id, v_event.intent, v_payload);

    UPDATE second_brain.update_journal
    SET state = 'applied',
        state_reason = 'APPLIED',
        applied_at = now(),
        replayable = false
    WHERE event_id = v_event.event_id;

    DELETE FROM second_brain.dead_letters WHERE event_id = v_event.event_id;

    INSERT INTO second_brain.update_outcomes(event_id, outcome_state, code, message, payload)
    VALUES (v_event.event_id, 'applied', COALESCE(v_result ->> 'code', 'APPLIED'), 'Event applied successfully', v_result);

    RETURN jsonb_build_object(
      'ok', true,
      'code', COALESCE(v_result ->> 'code', 'APPLIED'),
      'message', 'Event applied successfully',
      'data', jsonb_build_object('event_id', v_event.event_id, 'result', v_result),
      'meta', jsonb_build_object('journal_offset', v_event.journal_offset, 'trace_id', v_event.trace_id)
    );
  EXCEPTION
    WHEN OTHERS THEN
      UPDATE second_brain.update_journal
      SET state = 'dead_letter',
          state_reason = SQLERRM,
          replayable = true
      WHERE event_id = v_event.event_id;

      INSERT INTO second_brain.dead_letters(event_id, last_error, envelope)
      VALUES (
        v_event.event_id,
        SQLERRM,
        jsonb_build_object(
          'event_id', v_event.event_id,
          'intent', v_event.intent,
          'request', v_event.request,
          'error', SQLERRM,
          'failed_at', now()
        )
      )
      ON CONFLICT (event_id)
      DO UPDATE SET
        last_failed_at = now(),
        failure_count = second_brain.dead_letters.failure_count + 1,
        last_error = EXCLUDED.last_error,
        envelope = EXCLUDED.envelope;

      INSERT INTO second_brain.update_outcomes(event_id, outcome_state, code, message, payload)
      VALUES (
        v_event.event_id,
        'dead_letter',
        'APPLY_FAILED',
        SQLERRM,
        jsonb_build_object('error', SQLERRM)
      );

      RETURN jsonb_build_object(
        'ok', false,
        'code', 'APPLY_FAILED',
        'message', SQLERRM,
        'error', jsonb_build_object('event_id', v_event.event_id),
        'meta', jsonb_build_object('journal_offset', v_event.journal_offset, 'trace_id', v_event.trace_id)
      );
  END;
END;
$$;


