--
-- Name: ensure_entity(text, text, text, jsonb); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.ensure_entity(p_entity_type text, p_name text, p_external_ref text DEFAULT NULL::text, p_properties jsonb DEFAULT '{}'::jsonb) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_natural_key text;
  v_entity_id uuid;
BEGIN
  IF p_entity_type IS NULL OR trim(p_entity_type) = '' THEN
    RAISE EXCEPTION 'entity_type is required';
  END IF;

  IF p_name IS NULL OR trim(p_name) = '' THEN
    RAISE EXCEPTION 'name is required';
  END IF;

  v_natural_key := second_brain.make_natural_key(p_entity_type, p_name, p_external_ref);

  INSERT INTO second_brain.entities(entity_type, name, natural_key, external_ref, properties)
  VALUES (p_entity_type, p_name, v_natural_key, p_external_ref, COALESCE(p_properties, '{}'::jsonb))
  ON CONFLICT (natural_key)
  DO UPDATE SET
    entity_type = EXCLUDED.entity_type,
    name = EXCLUDED.name,
    external_ref = EXCLUDED.external_ref,
    properties = second_brain.entities.properties || EXCLUDED.properties,
    status = 'active'
  RETURNING entity_id INTO v_entity_id;

  RETURN v_entity_id;
END;
$$;


ALTER FUNCTION second_brain.ensure_entity(p_entity_type text, p_name text, p_external_ref text, p_properties jsonb) OWNER TO postgres;

--
-- Name: log_event(jsonb); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.log_event(p_request jsonb) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_event_id uuid;
  v_idempotency_key text;
  v_trace_id text;
  v_intent text;
  v_risk_level text;
  v_source_id text;
  v_created_by text;
  v_dry_run boolean;
BEGIN
  IF p_request IS NULL THEN
    RAISE EXCEPTION 'request is required';
  END IF;

  v_intent := COALESCE(p_request ->> 'intent', '');
  IF v_intent NOT IN ('add_entity','link_entities','add_memory','update_memory','deprecate') THEN
    RAISE EXCEPTION 'intent must be one of add_entity, link_entities, add_memory, update_memory, deprecate';
  END IF;

  v_idempotency_key := COALESCE(
    NULLIF(trim(p_request ->> 'idempotency_key'), ''),
    encode(digest(p_request::text, 'sha256'), 'hex')
  );
  v_trace_id := COALESCE(NULLIF(trim(p_request ->> 'trace_id'), ''), gen_random_uuid()::text);
  v_risk_level := COALESCE(NULLIF(trim(p_request ->> 'risk_level'), ''), 'medium');
  IF v_risk_level NOT IN ('low','medium','high') THEN
    v_risk_level := 'medium';
  END IF;

  v_source_id := NULLIF(trim(p_request ->> 'source_id'), '');
  v_created_by := COALESCE(NULLIF(trim(p_request ->> 'created_by'), ''), 'agent');
  v_dry_run := COALESCE((p_request ->> 'dry_run')::boolean, false);

  IF v_source_id IS NOT NULL THEN
    PERFORM 1
    FROM second_brain.source_registry
    WHERE source_id = v_source_id;

    IF NOT FOUND THEN
      PERFORM second_brain.register_source(
        v_source_id,
        'manual',
        'platform',
        interval '1 day',
        jsonb_build_object('auto_registered', true)
      );
    END IF;
  END IF;

  SELECT event_id
  INTO v_event_id
  FROM second_brain.update_journal
  WHERE idempotency_key = v_idempotency_key;

  IF v_event_id IS NOT NULL THEN
    INSERT INTO second_brain.update_outcomes(event_id, outcome_state, code, message, payload)
    VALUES (
      v_event_id,
      'duplicate',
      'DUPLICATE_EVENT',
      'Event already exists in journal',
      jsonb_build_object('idempotency_key', v_idempotency_key)
    );
    RETURN v_event_id;
  END IF;

  INSERT INTO second_brain.update_journal(
    idempotency_key,
    trace_id,
    intent,
    request,
    source_id,
    created_by,
    risk_level,
    dry_run,
    state,
    state_reason,
    replayable
  )
  VALUES (
    v_idempotency_key,
    v_trace_id,
    v_intent,
    p_request,
    v_source_id,
    v_created_by,
    v_risk_level,
    v_dry_run,
    'received',
    'JOURNALED',
    true
  )
  RETURNING event_id INTO v_event_id;

  INSERT INTO second_brain.update_outcomes(event_id, outcome_state, code, message, payload)
  VALUES (
    v_event_id,
    'received',
    'EVENT_JOURNALED',
    'Event persisted to immutable journal',
    jsonb_build_object('idempotency_key', v_idempotency_key, 'trace_id', v_trace_id)
  );

  RETURN v_event_id;
END;
$$;


ALTER FUNCTION second_brain.log_event(p_request jsonb) OWNER TO postgres;

--
-- Name: make_natural_key(text, text, text); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.make_natural_key(p_entity_type text, p_name text, p_external_ref text DEFAULT NULL::text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT lower(
    COALESCE(p_entity_type, 'unknown') || ':' ||
    COALESCE(NULLIF(trim(p_external_ref), ''), regexp_replace(trim(COALESCE(p_name, 'unnamed')), '[^a-zA-Z0-9]+', '-', 'g'))
  );
$$;


ALTER FUNCTION second_brain.make_natural_key(p_entity_type text, p_name text, p_external_ref text) OWNER TO postgres;

--
-- Name: mark_source_scan(text, text, text); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.mark_source_scan(p_source_id text, p_health_state text, p_error text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE second_brain.source_registry
  SET health_state = p_health_state,
      last_scan_at = now(),
      last_success_at = CASE WHEN p_health_state = 'healthy' THEN now() ELSE last_success_at END,
      last_error = p_error
  WHERE source_id = p_source_id;
END;
$$;


