--
-- Name: process_intent(uuid, text, jsonb); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.process_intent(p_event_id uuid, p_intent text, p_payload jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_entity_id uuid;
  v_memory_id uuid;
  v_from_id uuid;
  v_to_id uuid;
  v_relation_type text;
  v_entity_keys text[];
  v_entity_refs uuid[];
BEGIN
  IF p_intent = 'add_entity' THEN
    v_entity_id := second_brain.ensure_entity(
      COALESCE(p_payload ->> 'entity_type', p_payload ->> 'type'),
      COALESCE(p_payload ->> 'name', p_payload ->> 'title'),
      p_payload ->> 'external_ref',
      COALESCE(p_payload -> 'properties', '{}'::jsonb)
    );

    RETURN jsonb_build_object('entity_id', v_entity_id, 'code', 'ENTITY_UPSERTED');
  END IF;

  IF p_intent = 'link_entities' THEN
    v_relation_type := COALESCE(NULLIF(trim(p_payload ->> 'relation_type'), ''), 'RELATES_TO');

    IF p_payload ? 'from_entity_id' THEN
      v_from_id := (p_payload ->> 'from_entity_id')::uuid;
    ELSE
      SELECT entity_id INTO v_from_id
      FROM second_brain.entities
      WHERE natural_key = p_payload ->> 'from_natural_key';
    END IF;

    IF p_payload ? 'to_entity_id' THEN
      v_to_id := (p_payload ->> 'to_entity_id')::uuid;
    ELSE
      SELECT entity_id INTO v_to_id
      FROM second_brain.entities
      WHERE natural_key = p_payload ->> 'to_natural_key';
    END IF;

    IF v_from_id IS NULL OR v_to_id IS NULL THEN
      RAISE EXCEPTION 'from_entity and to_entity are required and must exist';
    END IF;

    INSERT INTO second_brain.relationships(
      from_entity,
      relation_type,
      to_entity,
      properties,
      confidence_score
    )
    VALUES (
      v_from_id,
      v_relation_type,
      v_to_id,
      COALESCE(p_payload -> 'properties', '{}'::jsonb),
      COALESCE((p_payload ->> 'confidence_score')::numeric, 0.900)
    )
    ON CONFLICT (from_entity, relation_type, to_entity)
    DO UPDATE SET
      properties = second_brain.relationships.properties || EXCLUDED.properties,
      confidence_score = EXCLUDED.confidence_score;

    RETURN jsonb_build_object(
      'from_entity', v_from_id,
      'to_entity', v_to_id,
      'relation_type', v_relation_type,
      'code', 'RELATIONSHIP_UPSERTED'
    );
  END IF;

  IF p_intent = 'add_memory' THEN
    v_entity_keys := COALESCE(ARRAY(
      SELECT jsonb_array_elements_text(COALESCE(p_payload -> 'entity_natural_keys', '[]'::jsonb))
    ), ARRAY[]::text[]);

    v_entity_refs := COALESCE(ARRAY(
      SELECT e.entity_id
      FROM second_brain.entities e
      WHERE e.natural_key = ANY(v_entity_keys)
      ORDER BY e.created_at
    ), ARRAY[]::uuid[]);

    INSERT INTO second_brain.memory_records(
      title,
      content,
      source_path_or_url,
      entity_refs,
      tags,
      confidence_score,
      ttl_policy,
      approval_state,
      change_origin
    )
    VALUES (
      COALESCE(p_payload ->> 'title', 'Untitled memory'),
      COALESCE(p_payload ->> 'content', ''),
      p_payload ->> 'source_path_or_url',
      v_entity_refs,
      COALESCE(ARRAY(SELECT jsonb_array_elements_text(COALESCE(p_payload -> 'tags', '[]'::jsonb))), ARRAY[]::text[]),
      COALESCE((p_payload ->> 'confidence_score')::numeric, 0.700),
      COALESCE(p_payload ->> 'ttl_policy', 'persistent'),
      'applied',
      COALESCE(p_payload ->> 'change_origin', 'agent')
    )
    RETURNING memory_id INTO v_memory_id;

    RETURN jsonb_build_object('memory_id', v_memory_id, 'code', 'MEMORY_ADDED');
  END IF;

  IF p_intent = 'update_memory' THEN
    v_memory_id := (p_payload ->> 'memory_id')::uuid;

    IF v_memory_id IS NULL THEN
      RAISE EXCEPTION 'memory_id is required for update_memory';
    END IF;

    UPDATE second_brain.memory_records
    SET
      title = COALESCE(p_payload ->> 'title', title),
      content = COALESCE(p_payload ->> 'content', content),
      source_path_or_url = COALESCE(p_payload ->> 'source_path_or_url', source_path_or_url),
      tags = COALESCE(ARRAY(SELECT jsonb_array_elements_text(COALESCE(p_payload -> 'tags', to_jsonb(tags)))), tags),
      confidence_score = COALESCE((p_payload ->> 'confidence_score')::numeric, confidence_score),
      ttl_policy = COALESCE(p_payload ->> 'ttl_policy', ttl_policy),
      approval_state = COALESCE(p_payload ->> 'approval_state', approval_state)
    WHERE memory_id = v_memory_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'memory_id % not found', v_memory_id;
    END IF;

    RETURN jsonb_build_object('memory_id', v_memory_id, 'code', 'MEMORY_UPDATED');
  END IF;

  IF p_intent = 'deprecate' THEN
    IF p_payload ? 'memory_id' THEN
      v_memory_id := (p_payload ->> 'memory_id')::uuid;
      UPDATE second_brain.memory_records
      SET is_deprecated = true,
          approval_state = 'applied'
      WHERE memory_id = v_memory_id;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'memory_id % not found', v_memory_id;
      END IF;

      RETURN jsonb_build_object('memory_id', v_memory_id, 'code', 'MEMORY_DEPRECATED');
    END IF;

    IF p_payload ? 'entity_natural_key' THEN
      UPDATE second_brain.entities
      SET status = 'deprecated'
      WHERE natural_key = p_payload ->> 'entity_natural_key';

      IF NOT FOUND THEN
        RAISE EXCEPTION 'entity_natural_key % not found', p_payload ->> 'entity_natural_key';
      END IF;

      RETURN jsonb_build_object('entity_natural_key', p_payload ->> 'entity_natural_key', 'code', 'ENTITY_DEPRECATED');
    END IF;

    RAISE EXCEPTION 'deprecate requires memory_id or entity_natural_key';
  END IF;

  RAISE EXCEPTION 'Unsupported intent %', p_intent;
END;
$$;


ALTER FUNCTION second_brain.process_intent(p_event_id uuid, p_intent text, p_payload jsonb) OWNER TO postgres;

--
-- Name: register_source(text, text, text, interval, jsonb); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.register_source(p_source_id text, p_source_type text, p_owner text, p_scan_frequency interval DEFAULT '1 day'::interval, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS text
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO second_brain.source_registry (
    source_id,
    source_type,
    owner,
    scan_frequency,
    health_state,
    schema_version,
    metadata,
    last_scan_at,
    last_success_at,
    last_error
  )
  VALUES (
    p_source_id,
    p_source_type,
    p_owner,
    p_scan_frequency,
    'healthy',
    'v1',
    COALESCE(p_metadata, '{}'::jsonb),
    now(),
    now(),
    NULL
  )
  ON CONFLICT (source_id)
  DO UPDATE SET
    source_type = EXCLUDED.source_type,
    owner = EXCLUDED.owner,
    scan_frequency = EXCLUDED.scan_frequency,
    health_state = 'healthy',
    metadata = second_brain.source_registry.metadata || EXCLUDED.metadata,
    last_scan_at = now(),
    last_success_at = now(),
    last_error = NULL;

  RETURN p_source_id;
END;
$$;


ALTER FUNCTION second_brain.register_source(p_source_id text, p_source_type text, p_owner text, p_scan_frequency interval, p_metadata jsonb) OWNER TO postgres;

--
-- Name: replay_dead_letters(integer); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.replay_dead_letters(p_limit integer DEFAULT 50) RETURNS TABLE(event_id uuid, result jsonb)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_event_id uuid;
BEGIN
  FOR v_event_id IN
    SELECT d.event_id
    FROM second_brain.dead_letters d
    JOIN second_brain.update_journal j ON j.event_id = d.event_id
    WHERE j.replayable = true
    ORDER BY d.first_failed_at
    LIMIT GREATEST(1, p_limit)
  LOOP
    event_id := v_event_id;
    result := second_brain.apply_event(v_event_id);
    RETURN NEXT;
  END LOOP;
END;
$$;


ALTER FUNCTION second_brain.replay_dead_letters(p_limit integer) OWNER TO postgres;

--
-- Name: store_reconciliation_report(jsonb, jsonb, jsonb, jsonb, jsonb, jsonb, jsonb); Type: FUNCTION; Schema: second_brain; Owner: postgres
--

CREATE FUNCTION second_brain.store_reconciliation_report(p_source_snapshot jsonb, p_missing_in_graph jsonb, p_stale_in_graph jsonb, p_conflicts jsonb, p_auto_fixed jsonb, p_manual_review jsonb, p_summary jsonb) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_report_id uuid;
BEGIN
  INSERT INTO second_brain.reconciliation_reports(
    source_snapshot,
    missing_in_graph,
    stale_in_graph,
    conflicts,
    auto_fixed,
    manual_review,
    summary
  )
  VALUES (
    COALESCE(p_source_snapshot, '{}'::jsonb),
    COALESCE(p_missing_in_graph, '[]'::jsonb),
    COALESCE(p_stale_in_graph, '[]'::jsonb),
    COALESCE(p_conflicts, '[]'::jsonb),
    COALESCE(p_auto_fixed, '[]'::jsonb),
    COALESCE(p_manual_review, '[]'::jsonb),
    COALESCE(p_summary, '{}'::jsonb)
  )
  RETURNING report_id INTO v_report_id;

  RETURN v_report_id;
END;
$$;


ALTER FUNCTION second_brain.store_reconciliation_report(p_source_snapshot jsonb, p_missing_in_graph jsonb, p_stale_in_graph jsonb, p_conflicts jsonb, p_auto_fixed jsonb, p_manual_review jsonb, p_summary jsonb) OWNER TO postgres;

