-- Name: categories; Type: TABLE; Schema: crm; Owner: postgres
--

CREATE TABLE crm.categories (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name text NOT NULL,
    direction text NOT NULL,
    active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT categories_direction_check CHECK ((direction = ANY (ARRAY['income'::text, 'expense'::text, 'both'::text])))
);


ALTER TABLE crm.categories OWNER TO postgres;

--
-- Name: contact_tags; Type: TABLE; Schema: crm; Owner: postgres
--

CREATE TABLE crm.contact_tags (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
