    tag_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE crm.contact_tags OWNER TO postgres;

--
-- Name: contacts; Type: TABLE; Schema: crm; Owner: postgres
--

CREATE TABLE crm.contacts (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    full_name text NOT NULL,
    phone_raw text,
    phone_e164 text NOT NULL,
    email text,
    status text DEFAULT 'active'::text NOT NULL,
    id_number text,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT contacts_status_check CHECK ((status = ANY (ARRAY['active'::text, 'inactive'::text, 'do_not_contact'::text])))
);


ALTER TABLE crm.contacts OWNER TO postgres;

--
-- Name: interactions; Type: TABLE; Schema: crm; Owner: postgres
--

CREATE TABLE crm.interactions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    contact_id uuid NOT NULL,
    type text NOT NULL,
    status text DEFAULT 'open'::text NOT NULL,
    category_id uuid,
    summary text,
    next_action_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    CONSTRAINT interactions_status_check CHECK ((status = ANY (ARRAY['open'::text, 'done'::text, 'followup'::text]))),
    CONSTRAINT interactions_type_check CHECK ((type = ANY (ARRAY['call'::text, 'whatsapp'::text, 'email'::text, 'meeting'::text, 'note'::text])))
);


ALTER TABLE crm.interactions OWNER TO postgres;

--
-- Name: payment_events_raw; Type: TABLE; Schema: crm; Owner: postgres
--

CREATE TABLE crm.payment_events_raw (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    provider text DEFAULT 'takbul'::text NOT NULL,
    received_at timestamp with time zone DEFAULT now() NOT NULL,
    external_ref text,
    payload_json jsonb NOT NULL,
    processed_status text DEFAULT 'new'::text NOT NULL,
    linked_transaction_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT payment_events_raw_processed_status_check CHECK ((processed_status = ANY (ARRAY['new'::text, 'processed'::text, 'failed'::text])))
);


ALTER TABLE crm.payment_events_raw OWNER TO postgres;

