--
-- Name: transactions; Type: TABLE; Schema: crm; Owner: postgres
--

CREATE TABLE crm.transactions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    contact_id uuid,
    direction text NOT NULL,
    amount numeric(14,2) NOT NULL,
    currency text DEFAULT 'ILS'::text NOT NULL,
    date timestamp with time zone NOT NULL,
    source text NOT NULL,
    external_ref text,
    category_id uuid,
    note text,
    status text DEFAULT 'new'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT transactions_direction_check CHECK ((direction = ANY (ARRAY['income'::text, 'expense'::text]))),
    CONSTRAINT transactions_source_check CHECK ((source = ANY (ARRAY['takbul'::text, 'bank_import'::text, 'manual'::text]))),
    CONSTRAINT transactions_status_check CHECK ((status = ANY (ARRAY['new'::text, 'categorized'::text, 'needs_review'::text])))
);


ALTER TABLE crm.transactions OWNER TO postgres;

