--
-- Name: update_journal; Type: TABLE; Schema: second_brain; Owner: postgres
--

CREATE TABLE second_brain.update_journal (
    event_id uuid DEFAULT gen_random_uuid() NOT NULL,
    journal_offset bigint NOT NULL,
    idempotency_key text NOT NULL,
    trace_id text NOT NULL,
    intent text NOT NULL,
    request jsonb NOT NULL,
    source_id text,
    created_by text DEFAULT 'agent'::text NOT NULL,
    risk_level text DEFAULT 'medium'::text NOT NULL,
    dry_run boolean DEFAULT false NOT NULL,
    state text DEFAULT 'received'::text NOT NULL,
    state_reason text,
    replayable boolean DEFAULT true NOT NULL,
    received_at timestamp with time zone DEFAULT now() NOT NULL,
    applied_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT update_journal_intent_check CHECK ((intent = ANY (ARRAY['add_entity'::text, 'link_entities'::text, 'add_memory'::text, 'update_memory'::text, 'deprecate'::text]))),
    CONSTRAINT update_journal_risk_level_check CHECK ((risk_level = ANY (ARRAY['low'::text, 'medium'::text, 'high'::text]))),
    CONSTRAINT update_journal_state_check CHECK ((state = ANY (ARRAY['received'::text, 'proposed'::text, 'applied'::text, 'rejected'::text, 'duplicate'::text, 'dead_letter'::text])))
);


ALTER TABLE second_brain.update_journal OWNER TO postgres;

