--

ALTER TABLE second_brain.update_outcomes ALTER COLUMN outcome_id ADD GENERATED ALWAYS AS IDENTITY (
    SEQUENCE NAME second_brain.update_outcomes_outcome_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);


--
-- Name: v_event_status; Type: VIEW; Schema: second_brain; Owner: postgres
--

CREATE VIEW second_brain.v_event_status AS
 SELECT j.event_id,
    j.journal_offset,
    j.intent,
    j.risk_level,
    j.state,
    j.state_reason,
    j.replayable,
    j.received_at,
    j.applied_at,
    j.trace_id,
    j.idempotency_key,
    ( SELECT o.code
           FROM second_brain.update_outcomes o
          WHERE (o.event_id = j.event_id)
          ORDER BY o.created_at DESC
         LIMIT 1) AS last_code
   FROM second_brain.update_journal j
  ORDER BY j.received_at DESC;


ALTER TABLE second_brain.v_event_status OWNER TO postgres;

